import { WorkflowContext, StepOutput } from 'mastra/workflows';

import { scanForInjection } from './injection-scanner';

export async function detectWorkflowInjection(ctx: WorkflowContext, output: StepOutput): Promise<boolean> {
  // Scan all string outputs for common injection patterns
  const payloads = ['ignore', 'forget', 'override', 'system', 'you are', 'act as'];

  for (const [key, value] of Object.entries(output.data)) {
    if (typeof value === 'string') {
      for (const payload of payloads) {
        if (value.toLowerCase().includes(payload) && 
            (value.includes('previous') || value.includes('instructions'))) {
          console.warn(`Injection detected in workflow step ${ctx.currentStep}: ${value.slice(0, 100)}...`);
          return true;
        }
      }
    }
  }
  return false;
}

import { AgentToolCall, ToolResponse } from 'mastra/agents';

export function validateToolResponse(call: AgentToolCall, response: ToolResponse): boolean {
  const suspiciousPatterns = [
    /\b(ignore|forget|override|system|you are|act as)\b/gi,
    /previous instructions/i,
    /do not tell|don't reveal/i,
    /from now on/i
  ];

  const content = response.content?.toString() || '';

  return !suspiciousPatterns.some(pattern => pattern.test(content));
}

export function logSuspiciousToolResponse(call: AgentToolCall, response: ToolResponse) {
  if (!validateToolResponse(call, response)) {
    console.error('🚨 Tool injection detected:', {
      tool: call.toolName,
      input: call.input,
      suspiciousContent: response.content
    });
  }
}

import { MemoryRetrieval } from 'mastra/memory';

export function auditMemoryRetrieval(retrieval: MemoryRetrieval[]): boolean {
  const injectionScore = (content: string): number => {
    const indicators = ['system:', 'override', 'ignore previous', 'you are now'];
    return indicators.filter(indicator => 
      content.toLowerCase().includes(indicator.toLowerCase())
    ).length;
  };

  for (const item of retrieval) {
    if (injectionScore(item.content) >= 2) {
      console.warn('Memory injection risk:', item.content.slice(0, 200));
      return true;
    }
  }
  return false;
}

