import { WorkflowMiddleware } from 'mastra/workflows';

import { sanitizePrompt } from './prompt-sanitizer';

export const injectionPreventionMiddleware: WorkflowMiddleware = async (ctx, next) => {
  // Sanitize output before it becomes input for next step
  if (ctx.output) {
    ctx.output.data = {
      ...ctx.output.data,
      sanitizedContent: sanitizePrompt(JSON.stringify(ctx.output.data))
    };
  }

  await next();
};

export function sanitizePrompt(input: string): string {
  const dangerousPatterns = [
    /ignore previous instructions/gi,
    /you are now.*?\b(?:helpful|malicious|evil)/gi,
    /from now on.*?do/gi,
    /system:.*?\n\n/gi
  ];

  return dangerousPatterns.reduce((clean, pattern) => 
    clean.replace(pattern, '[SANITIZED]'), input
  );
}

import { AgentTool, ToolResponse } from 'mastra/agents';

export function createSafeTool<T extends AgentTool>(tool: T): T {
  const safeExecute = async (input: any): Promise<ToolResponse> => {
    const rawResponse = await tool.execute(input);

    // Validate and sanitize
    const safeContent = sanitizeToolOutput(rawResponse.content);

    return {
      ...rawResponse,
      content: safeContent
    };
  };

  return {
    ...tool,
    execute: safeExecute as any
  };
}

function sanitizeToolOutput(content: any): string {
  if (typeof content !== 'string') return String(content);

  // Remove executable prompt fragments
  return content
    .replace(/\b(?:ignore|override|forget|system:)\s*/gi, '[REMOVED]')
    .replace(/you are now.*?\./gi, '[ROLE SANITIZED]')
    .replace(/from now on/gi, '[INSTRUCTION REMOVED]');
}

import { MemoryFilter } from 'mastra/memory';

export const safeMemoryFilter: MemoryFilter = {
  filter: (retrievals) => {
    return retrievals.filter(item => {
      const score = calculateInjectionRisk(item.content);
      return score < 0.7; // Threshold for safe content
    });
  }
};

function calculateInjectionRisk(content: string): number {
  const indicators = [
    'ignore previous',
    'you are now',
    'system:',
    'override',
    'forget'
  ];

  const matches = indicators.filter(ind => 
    content.toLowerCase().includes(ind)
  );

  return matches.length / indicators.length;
}

