import { Vex } from '@vex_dev/sdk';
import { Agent, Workflow } from 'mastra';

// Initialize Vex for Mastra
const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!,
});

// Protect Mastra agent pipeline
export class SecureMastraAgent extends Agent {
  constructor() {
    super();

    // Vex middleware - blocks injections automatically
    this.use(vex.middleware({
      framework: 'mastra',
      blockOnRisk: 'high',
      sanitize: true,
      logPayloads: true
    }));
  }
}

// Protect workflows
export const secureWorkflow = new Workflow()
  .use(vex.workflowMiddleware())
  .addStep('userInput', userInputStep)
  .addStep('process', processStep)
  .addStep('respond', respondStep);
